class InMemoryOrderStore:
    def __init__(self) -> None:
        self._orders: List[OrderRecord] = []
        self._counter = 0

    def create(self, order: OrderRecord) -> OrderRecord:
        self._orders.append(order)
        return order

    def next_order_id(self) -> str:
        self._counter += 1
        return f"ORD-{self._counter:06d}"

    @property
    def orders(self) -> List[OrderRecord]:
        return list(self._orders)


class PaymentGateway:
    def charge(self, amount: Decimal, payment_method: Dict[str, Any], user: User) -> PaymentResult:
        if amount <= Decimal("0.00"):
            return PaymentResult(
                success=True,
                transaction_id=f"FREE-{user.user_id}",
                status="paid",
                message="No charge required",
            )

        if not payment_method or not payment_method.get("token"):
            return PaymentResult(
                success=False,
                status="declined",
                message="Missing payment token",
            )

        if payment_method.get("simulate_failure"):
            return PaymentResult(
                success=False,
                status="declined",
                message="Payment was declined",
            )

        token = str(payment_method["token"])
        return PaymentResult(
            success=True,
            transaction_id=f"TXN-{user.user_id}-{token[-6:]}",
            status="paid",
            message="Payment processed successfully",
        )


class CheckoutService:
    def __init__(
        self,
        discount_catalog: Sequence[DiscountCode],
        order_store: InMemoryOrderStore,
        payment_gateway: PaymentGateway,
    ) -> None:
        self.discount_catalog = {d.normalized_code(): d for d in discount_catalog}
        self.order_store = order_store
        self.payment_gateway = payment_gateway

    def checkout(
        self,
        user: User,
        cart_items: Sequence[CartItem],
        payment_method: Dict[str, Any],
        tax_rate: Decimal | int | float | str,
        discount_code: Optional[str] = None,
        currency: str = "USD",
        metadata: Optional[Dict[str, Any]] = None,
    ) -> OrderRecord:
        validated = self.validate_cart_items(cart_items, currency=currency)
        discount = self.apply_discount_code(
            user=user,
            validated_cart=validated,
            discount_code=discount_code,
        )
        tax = self.calculate_tax(
            discount_result=discount,
            tax_rate=money(tax_rate),
        )
        payment = self.process_payment(
            user=user,
            tax_result=tax,
            payment_method=payment_method,
        )
        order = self.create_order_record(
            user=user,
            validated_cart=validated,
            discount_result=discount,
            tax_result=tax,
            payment_result=payment,
            metadata=metadata or {},
        )
        return order

    def validate_cart_items(self, cart_items: Sequence[CartItem], currency: str = "USD") -> ValidatedCart:
        if not cart_items:
            raise ValidationError("Cart cannot be empty")

        validated_items: List[CartItem] = []
        subtotal = Decimal("0.00")
        taxable_subtotal = Decimal("0.00")

        for item in cart_items:
            if item.quantity <= 0:
                raise ValidationError(f"Invalid quantity for SKU {item.sku}")
            if item.unit_price < Decimal("0.00"):
                raise ValidationError(f"Invalid unit price for SKU {item.sku}")
            if not item.active:
                raise ValidationError(f"Item {item.sku} is inactive")
            if item.inventory_available < item.quantity:
                raise ValidationError(f"Insufficient inventory for SKU {item.sku}")

            validated_items.append(item)
            line_subtotal = item.subtotal()
            subtotal += line_subtotal
            if item.taxable:
                taxable_subtotal += line_subtotal

        subtotal = money(subtotal)
        taxable_subtotal = money(taxable_subtotal)

        if subtotal <= Decimal("0.00"):
            raise ValidationError("Cart subtotal must be greater than zero")

        return ValidatedCart(
            items=validated_items,
            subtotal=subtotal,
            taxable_subtotal=taxable_subtotal,
            currency=currency,
        )

    def apply_discount_code(
        self,
        user: User,
        validated_cart: ValidatedCart,
        discount_code: Optional[str],
    ) -> DiscountResult:
        if not discount_code:
            return DiscountResult(
                code=None,
                discount_amount=Decimal("0.00"),
                subtotal_after_discount=validated_cart.subtotal,
                taxable_subtotal_after_discount=validated_cart.taxable_subtotal,
                details={"applied": False},
            )

        normalized = discount_code.strip().upper()
        discount = self.discount_catalog.get(normalized)
        if not discount or not discount.active:
            raise ValidationError("Invalid or inactive discount code")

        self._validate_discount_permissions(user, discount)

        if validated_cart.subtotal < money(discount.min_subtotal):
            raise ValidationError("Cart does not meet minimum subtotal for this discount")

        base_amount = validated_cart.taxable_subtotal if discount.applies_to_taxable_only else validated_cart.subtotal

        if discount.kind == "percent":
            if discount.amount < Decimal("0.00") or discount.amount > Decimal("100.00"):
                raise ValidationError("Invalid percentage discount amount")
            discount_amount = money(base_amount * (discount.amount / Decimal("100")))
        elif discount.kind == "fixed":
            if discount.amount < Decimal("0.00"):
                raise ValidationError("Invalid fixed discount amount")
            discount_amount = money(min(discount.amount, base_amount))
        else:
            raise ValidationError("Unsupported discount type")

        discount_amount = min(discount_amount, validated_cart.subtotal)
        subtotal_after_discount = money(max(Decimal("0.00"), validated_cart.subtotal - discount_amount))

        if validated_cart.subtotal == Decimal("0.00"):
            taxable_discount_share = Decimal("0.00")
        elif discount.applies_to_taxable_only:
            taxable_discount_share = min(discount_amount, validated_cart.taxable_subtotal)
        else:
            taxable_ratio = validated_cart.taxable_subtotal / validated_cart.subtotal
            taxable_discount_share = money(discount_amount * taxable_ratio)

        taxable_subtotal_after_discount = money(
            max(Decimal("0.00"), validated_cart.taxable_subtotal - taxable_discount_share)
        )

        return DiscountResult(
            code=normalized,
            discount_amount=money(discount_amount),
            subtotal_after_discount=subtotal_after_discount,
            taxable_subtotal_after_discount=taxable_subtotal_after_discount,
            details={
                "applied": True,
                "kind": discount.kind,
                "amount": money(discount.amount),
                "admin_only": discount.admin_only,
                "allowed_tiers": list(discount.allowed_tiers) if discount.allowed_tiers else None,
                "applies_to_taxable_only": discount.applies_to_taxable_only,
            },
        )

    def calculate_tax(self, discount_result: DiscountResult, tax_rate: Decimal) -> TaxResult:
        if tax_rate < Decimal("0.00") or tax_rate > Decimal("1.00"):
            raise ValidationError("Tax rate must be between 0.00 and 1.00")

        tax_amount = money(discount_result.taxable_subtotal_after_discount * tax_rate)
        total_before_payment = money(discount_result.subtotal_after_discount + tax_amount)

        return TaxResult(
            tax_rate=money(tax_rate),
            tax_amount=tax_amount,
            total_before_payment=total_before_payment,
        )

    def process_payment(
        self,
        user: User,
        tax_result: TaxResult,
        payment_method: Dict[str, Any],
    ) -> PaymentResult:
        result = self.payment_gateway.charge(
            amount=tax_result.total_before_payment,
            payment_method=payment_method,
            user=user,
        )
        if not result.success or not result.transaction_id:
            raise PaymentError(result.message or "Payment processing failed")
        return result

    def create_order_record(
        self,
        user: User,
        validated_cart: ValidatedCart,
        discount_result: DiscountResult,
        tax_result: TaxResult,
        payment_result: PaymentResult,
        metadata: Dict[str, Any],
    ) -> OrderRecord:
        order = OrderRecord(
            order_id=self.order_store.next_order_id(),
            user_id=user.user_id,
            items=[
                {
                    "sku": item.sku,
                    "name": item.name,
                    "unit_price": money(item.unit_price),
                    "quantity": item.quantity,
                    "taxable": item.taxable,
                    "line_total": item.subtotal(),
                }
                for item in validated_cart.items
            ],
            subtotal=validated_cart.subtotal,
            discount_code=discount_result.code,
            discount_amount=discount_result.discount_amount,
            taxable_subtotal=discount_result.taxable_subtotal_after_discount,
            tax_rate=tax_result.tax_rate,
            tax_amount=tax_result.tax_amount,
            total=tax_result.total_before_payment,
            currency=validated_cart.currency,
            payment_transaction_id=payment_result.transaction_id or "",
            payment_status=payment_result.status,
            metadata=metadata,
        )
        return self.order_store.create(order)

    def _validate_discount_permissions(self, user: User, discount: DiscountCode) -> None:
        if discount.admin_only and not user.is_admin:
            raise AuthorizationError("This discount code is restricted to admins")

        if discount.allowed_tiers:
            allowed = {tier.lower() for tier in discount.allowed_tiers}
            if user.tier.lower() not in allowed:
                raise AuthorizationError("User tier is not permitted to use this discount code")


